noncompliant:
// Ternary conditions without parentheses
int val = condition ? a + b : c * d; // Noncompliant - unclear
bool check = x > 0 ? true : y < 0 ? false : true; // Noncompliant

compliant:
// Clear ternary expressions
int val = condition ? (a + b) : (c * d); // Compliant
bool check = (x > 0) ? true : ((y < 0) ? false : true); // Compliant
